/// <summary>
///
/// </summary>
/// <param name="args"></param>
[PostHandlerFor(classStr(InterCompanyGoodsInTransitTransDP), methodStr(InterCompanyGoodsInTransitTransDP, processReport))]
public static void InterCompanyGoodsInTransitTransDP_Post_processReport(XppPrePostArgs args)
{
    InterCompanyGoodsInTransitTransDP   dpbuffer        =   args.getThis();
    InterCompanyGoodsInTransitTmp       intercomptmp    =   dpbuffer.getInterCompanyGoodsInTransitTmp();
    InterCompanyGoodsInTransitContract  contract        =   dpbuffer.parmDataContract();
    InventDim                           inventDim;
    VendPackingSlipJour                 vendPackingSlipJour = VendPackingSlipJour::findFromPurchId(intercomptmp.PurchId);
    VendPackingSlipTrans                vendPackingSlipTrans;
    boolean                             grade,size,colour,brand;

    select inventDimId from vendPackingSlipTrans
        where vendPackingSlipTrans.vendPackingslipJour == vendPackingSlipJour.RecId
        join inventDim
        where inventDim.inventDimId == vendPackingSlipTrans.InventDimId;

    grade   =   contract.parmViewConfigId();

    if(grade)
    {
        update_recordset intercomptmp
            setting Grade   = inventDim.configId;
    }

    size    =   contract.parmViewInventSizeId();

    if(size)
    {
        update_recordset intercomptmp
            setting Size = inventDim.InventSizeId;
    }

    colour  =   contract.parmViewInventColorId();

    if(colour)
    {
        update_recordset intercomptmp
            setting OriginDim = inventDim.InventColorId;
    }

    brand   =   contract.parmViewInventStyleId();

    if(brand)
    {
        update_recordset intercomptmp
            setting Brand = inventDim.InventStyleId;
    }
}
